#include <iostream>
#include <fstream>
#include <cstring>
#include <vector>
using namespace std;

struct Student {
    char name[50];
    int rollNo;
    double marks;
};

void addStudent(const string& filename) {
    Student s;
    cout << "Name: "; cin.getline(s.name, 50);
    cout << "Roll No: "; cin >> s.rollNo;
    cout << "Marks: "; cin >> s.marks;
    cin.ignore();

    ofstream file(filename, ios::binary | ios::app);
    file.write(reinterpret_cast<char*>(&s), sizeof(Student));
    file.close();
    cout << "Student added." << endl;
}

void displayAll(const string& filename) {
    ifstream file(filename, ios::binary);
    Student s;
    cout << "\nAll Students:" << endl;
    while (file.read(reinterpret_cast<char*>(&s), sizeof(Student))) {
        cout << "Roll: " << s.rollNo << ", Name: " << s.name
             << ", Marks: " << s.marks << endl;
    }
    file.close();
}

void searchByRoll(const string& filename, int roll) {
    ifstream file(filename, ios::binary);
    Student s;
    bool found = false;
    while (file.read(reinterpret_cast<char*>(&s), sizeof(Student))) {
        if (s.rollNo == roll) {
            cout << "Found: " << s.name << ", Marks: " << s.marks << endl;
            found = true;
            break;
        }
    }
    if (!found) cout << "Student not found." << endl;
    file.close();
}

int main() {
    // Demonstration with pre-built data
    string filename = "records.dat";
    ofstream clear(filename, ios::binary | ios::trunc);
    clear.close();

    Student students[] = {
        {"Arjun", 101, 85.5},
        {"Priya", 102, 92.0},
        {"Kiran", 103, 78.3}
    };
    ofstream out(filename, ios::binary);
    for (auto& s : students)
        out.write(reinterpret_cast<char*>(&s), sizeof(Student));
    out.close();

    displayAll(filename);
    cout << endl;
    searchByRoll(filename, 102);
