}

#include <iostream>
#include <fstream>
#include <sstream>
#include <string>
#include <vector>
using namespace std;

int main() {
    // Write CSV
    ofstream out("marks.csv");
    out << "Name,Maths,Physics,Chemistry" << endl;
    out << "Arjun,85,90,78" << endl;
    out << "Priya,92,88,95" << endl;
    out << "Kiran,78,82,80" << endl;
    out.close();

    // Read and parse CSV
    ifstream in("marks.csv");
    string line;
    getline(in, line);  // skip header
    cout << "Student Report:" << endl;
    cout << "---------------------------" << endl;

    while (getline(in, line)) {
        stringstream ss(line);
        string name, token;
        getline(ss, name, ',');
        vector<int> marks;
        while (getline(ss, token, ','))
            marks.push_back(stoi(token));

        int total = 0;
        for (int m : marks) total += m;
        double avg = (double)total / marks.size();

        cout << name << ": Total=" << total
             << ", Average=" << avg << endl;
    }
    in.close();
    return 0;
}

#include <iostream>
#include <fstream>
using namespace std;

int main() {
    // Create source file
    ofstream src("source.txt");
    src << "This is the source file content." << endl;
    src << "It has multiple lines." << endl;
    src.close();

    // Copy file using binary mode
    ifstream in("source.txt", ios::binary);
    ofstream out("copy.txt", ios::binary);

    if (!in.is_open() || !out.is_open()) {
        cerr << "Error opening files!" << endl;
        return 1;
    }

    // Method 1: Read and write char by char
    // char ch;
    // while (in.get(ch)) out.put(ch);

    // Method 2: Read in chunks (more efficient)
    char buffer[1024];
    while (in.read(buffer, sizeof(buffer))) {
        out.write(buffer, in.gcount());
    }
    // Write remaining bytes (last chunk may be smaller)
    out.write(buffer, in.gcount());

    in.close();
    out.close();

    // Verify copy
    ifstream verify("copy.txt");
    string line;
    while (getline(verify, line))
        cout << line << endl;
    verify.close();
    return 0;
}

#include <iostream>
#include <fstream>
#include <ctime>
#include <string>
using namespace std;

class Logger {
    string filename;
public:
    Logger(const string& fname) : filename(fname) {}

    void log(const string& level, const string& message) {
        ofstream file(filename, ios::app);
        time_t now = time(nullptr);
        char timestamp[26];
        ctime_r(&now, timestamp);
        timestamp[24] = '\0';  // remove newline

        file << "[" << timestamp << "] " << level << ": " << message << endl;
        file.close();
    }

    void info(const string& msg) { log("INFO", msg); }
    void warn(const string& msg) { log("WARN", msg); }
    void error(const string& msg) { log("ERROR", msg); }

    void display() {
        ifstream file(filename);
        string line;
        while (getline(file, line))
            cout << line << endl;
        file.close();
    }
};

int main() {
    Logger logger("app.log");
    logger.info("Application started");
    logger.info("User Arjun logged in");
    logger.warn("Memory usage above 80%");
    logger.error("Database connection failed");
    logger.info("Retrying connection...");

    cout << "Log contents:" << endl;
    logger.display();
    return 0;
}

#include <iostream>
#include <fstream>
#include <cstring>
using namespace std;

struct Student {
    int rollNo;
    char name[30];
    double marks;
};

int main() {
    string filename = "students.dat";

    // Write 3 students
    Student students[] = {
        {101, "Arjun", 85.0},
        {102, "Priya", 78.0},
        {103, "Kiran", 90.0}
    };
    ofstream out(filename, ios::binary);
    for (auto& s : students)
        out.write(reinterpret_cast<char*>(&s), sizeof(Student));
    out.close();

    // Update record at index 1 (Priya's marks: 78 -> 95)
    fstream file(filename, ios::in | ios::out | ios::binary);
    Student update;
    int recordIndex = 1;

    // Seek to the record
    file.seekg(recordIndex * sizeof(Student), ios::beg);
    file.read(reinterpret_cast<char*>(&update), sizeof(Student));
    cout << "Before: " << update.name << ", Marks: " << update.marks << endl;

    // Modify and write back
    update.marks = 95.0;
    file.seekp(recordIndex * sizeof(Student), ios::beg);
    file.write(reinterpret_cast<char*>(&update), sizeof(Student));
    file.close();

    // Verify
    ifstream verify(filename, ios::binary);
    Student temp;
    while (verify.read(reinterpret_cast<char*>(&temp), sizeof(Student))) {
        cout << temp.rollNo << ": " << temp.name
             << ", Marks: " << temp.marks << endl;
    }
    verify.close();
    return 0;
}

#include <iostream>
#include <fstream>
using namespace std;

int main() {
    // Create test file
    ofstream out("test.txt");
    out << "Hello World";
    out.close();

    // Get file size using seekg and tellg
    ifstream file("test.txt", ios::binary);
    file.seekg(0, ios::end);       // seek to end
    streamsize size = file.tellg(); // get position = file size
    file.seekg(0, ios::beg);       // seek back to beginning

    cout << "File size: " << size << " bytes" << endl;

    // Read all content into string
    string content(size, '\0');
    file.read(&content[0], size);
    cout << "Content: " << content << endl;

    // Check state after reading everything
    char ch;
    file.get(ch);  // try to read past end
    if (file.eof())
        cout << "Reached end of file" << endl;
    if (file.fail())
        cout << "Read operation failed (expected at EOF)" << endl;
    if (!file.good())
        cout << "Stream is not in good state" << endl;
    file.close();
    return 0;
}

